mapper.select:
SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM work_orders
WHERE wo_number = #{woNumber}

    AND id != #{excludeId}

SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM lots
WHERE id = #{lotId}

SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM equipment
WHERE id = #{equipmentId}

SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM work_orders
WHERE lot_id = #{lotId}
  AND process_type = #{processType}
  AND status = 'DONE'

    AND id != #{excludeId}

SELECT a.id, a.work_order_id, w.wo_number, a.user_id, u.name AS user_name, a.role, a.start_at, a.end_at FROM work_assignments a LEFT JOIN work_orders w ON w.id = a.work_order_id LEFT JOIN users u ON u.id = a.user_id
WHERE a.work_order_id = #{workOrderId}
ORDER BY a.start_at DESC

SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM work_assignments
WHERE work_order_id = #{workOrderId}
  AND user_id = #{userId}

    AND id != #{excludeId}
